    { id: 57, difficulty: "dificil", question: { pt: "Qual a função da quimiocina CXCL13?", es: "¿CXCL13?" }, answer: { pt: "Atrai linfócitos B para os folículos.", es: "Atrae B a folículos." } },
    { id: 58, difficulty: "dificil", question: { pt: "Qual a função das quimiocinas CCL19 e CCL21?", es: "¿CCL19/21?" }, answer: { pt: "Atraem T e DCs para a paracórtex.", es: "Atraen T a paracórtex." } },
    { id: 59, difficulty: "dificil", question: { pt: "O que é a linfa de escape (leakage)?", es: "¿Linfa de escape?" }, answer: { pt: "Fluido que sai dos capilares sanguíneos mas não é coletado pelos linfáticos (gera edema).", es: "Fuga capilar." } },
    { id: 60, difficulty: "dificil", question: { pt: "Como a quilotórax ocorre?", es: "¿Quilotórax?" }, answer: { pt: "Acúmulo de quilo no espaço pleural devido à ruptura do ducto torácico.", es: "Quilo en pleura." } }
