    { id: 58, difficulty: "dificil", question: { pt: "O que é a imunoeletroforese?", es: "¿Inmunoelectroforesis?" }, answer: { pt: "Técnica que separa proteínas e usa anticorpos para identificá-las.", es: "Separa e identifica proteínas." } },
    { id: 59, difficulty: "dificil", question: { pt: "O que são imunocomplexos circulantes?", es: "¿Inmunocomplejos?" }, answer: { pt: "Agregados de antígeno-anticorpo no sangue que podem causar vasculites se não limpos.", es: "Agregados Ag-Ac en sangre." } },
    { id: 60, difficulty: "dificil", question: { pt: "Como a IgA inibe a adesão bacteriana?", es: "¿IgA y adhesión?" }, answer: { pt: "Bloqueando as adesinas (fímbrias) na superfície das bactérias.", es: "Bloquea fimbrias." } }
